import{_ as o,o as a,c as t,a0 as s}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"Relatório de Qualidade do Pipeline de Ingestão e Grafo T4","description":"","frontmatter":{},"headers":[],"relativePath":"99_Log_e_Sessoes/INGESTION_QUALITY_REPORT_2026-07-09.md","filePath":"99_Log_e_Sessoes/INGESTION_QUALITY_REPORT_2026-07-09.md","lastUpdated":1783623176000}'),r={name:"99_Log_e_Sessoes/INGESTION_QUALITY_REPORT_2026-07-09.md"};function d(n,e,i,c,l,u){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="relatorio-de-qualidade-do-pipeline-de-ingestao-e-grafo-t4" tabindex="-1">Relatório de Qualidade do Pipeline de Ingestão e Grafo T4 <a class="header-anchor" href="#relatorio-de-qualidade-do-pipeline-de-ingestao-e-grafo-t4" aria-label="Permalink to &quot;Relatório de Qualidade do Pipeline de Ingestão e Grafo T4&quot;">​</a></h1><p><strong>Data:</strong> 09 de Julho de 2026<br><strong>Status:</strong> ✅ RESOLVIDO E VALIDADO<br><strong>Contexto:</strong> Wave 2 Cognitive Leap (Ingestion Quality Audit)</p><hr><h2 id="_1-identificacao-e-resolucao-do-bug-de-sincronizacao-qdrant-critical-fix" tabindex="-1">1. Identificação e Resolução do Bug de Sincronização Qdrant (Critical Fix) <a class="header-anchor" href="#_1-identificacao-e-resolucao-do-bug-de-sincronizacao-qdrant-critical-fix" aria-label="Permalink to &quot;1. Identificação e Resolução do Bug de Sincronização Qdrant (Critical Fix)&quot;">​</a></h2><p>Durante a validação manual do pipeline semântico com ferramentas MCP (<code>nexus_query</code>), descobrimos um desalinhamento crítico na persistência vetorial:</p><ul><li><strong>Problema:</strong> O script de inicialização <code>init_qdrant_collections.sh</code> configurava as coleções com um único vetor anônimo (padrão do Qdrant). No entanto, o código de ingestão (<code>ingest.rs</code>) enviava os pontos usando vetores nomeados (<code>text_dense</code> e <code>text_sparse</code>).</li><li><strong>Sintoma:</strong> O Qdrant rejeitava silenciosamente todas as inserções de pontos (<code>Update operation declined: Wrong input: Not existing vector name error: text_dense</code>), retornando HTTP 200 OK de recebimento assíncrono para o <code>nexus-engine</code>. Isso resultava em coleções zeradas (0 pontos), quebrando completamente a busca semântica, apesar de o motor logar sucesso.</li><li><strong>Correção:</strong> Atualizamos o script [init_qdrant_collections.sh](file:///var/home/bruno/repos/NEXUS/scripts/init_qdrant_collections.sh) para especificar os esquemas de vetores nomeados <code>text_dense</code> (768d, Cosine) e <code>text_sparse</code>. Realizamos o expurgo completo dos bancos (Postgres <code>abstractions</code> / <code>blobs</code> / <code>links</code> e coleções Qdrant) para disparar uma re-ingestão limpa e sincronizada do repositório.</li></ul><hr><h2 id="_2-status-atual-da-ingestao" tabindex="-1">2. Status Atual da Ingestão <a class="header-anchor" href="#_2-status-atual-da-ingestao" aria-label="Permalink to &quot;2. Status Atual da Ingestão&quot;">​</a></h2><p>Após a reinicialização e correção do esquema, o pipeline está ingerindo o repositório do zero com sucesso. O status atual dos dados no banco <code>axiodb</code> é:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Nível de Abstração</th><th style="text-align:center;">Total de Linhas (PG)</th><th style="text-align:center;">Linhas Vetorizadas (Qdrant)</th><th style="text-align:left;">Status</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>L0 (Chunks Brutos)</strong></td><td style="text-align:center;">276</td><td style="text-align:center;">276</td><td style="text-align:left;">Sincronizado (Coleção <code>nexus_ghost</code>)</td></tr><tr><td style="text-align:left;"><strong>L1 (Assinatura AST)</strong></td><td style="text-align:center;">33</td><td style="text-align:center;">19</td><td style="text-align:left;">Em progresso (Coleção <code>nexus_ast</code>)</td></tr><tr><td style="text-align:left;"><strong>L2 (Sumário Semântico)</strong></td><td style="text-align:center;">11</td><td style="text-align:center;">8</td><td style="text-align:left;">Em progresso via Ollama (<code>qwen2.5-coder:1.5b</code>)</td></tr><tr><td style="text-align:left;"><strong>L4 (Nó de Arquivo)</strong></td><td style="text-align:center;">45</td><td style="text-align:center;">—</td><td style="text-align:left;">Estrutural (Apenas Relacional)</td></tr></tbody></table><hr><h2 id="_3-validacao-empirica-mcp-vs-banco-de-dados" tabindex="-1">3. Validação Empírica (MCP vs. Banco de Dados) <a class="header-anchor" href="#_3-validacao-empirica-mcp-vs-banco-de-dados" aria-label="Permalink to &quot;3. Validação Empírica (MCP vs. Banco de Dados)&quot;">​</a></h2><p>Executamos testes utilizando as ferramentas oficiais expostas pelo servidor MCP para validar a qualidade da busca e navegação topológica:</p><h3 id="a-busca-semantica-simples-nexus-query-em-nexus-ghost" tabindex="-1">A. Busca Semântica Simples (<code>nexus_query</code> em <code>nexus_ghost</code>) <a class="header-anchor" href="#a-busca-semantica-simples-nexus-query-em-nexus-ghost" aria-label="Permalink to &quot;A. Busca Semântica Simples (`nexus_query` em `nexus_ghost`)&quot;">​</a></h3><ul><li><strong>Query:</strong> <code>&quot;decay nomad&quot;</code></li><li><strong>Resultado do MCP:</strong> Retornou [nomad/decay.rs](file:///var/home/bruno/repos/NEXUS/services/coordinator/src/nomad/decay.rs) (Node ID <code>075867cf-40ad-447b-996f-c024bec4649b</code>) como o terceiro resultado com score de relevância alto, junto com outros Nomads adjacentes.</li><li><strong>Validação:</strong> O sumário L2 gerado pelo Ollama preservou com exatidão a responsabilidade do módulo.</li></ul><h3 id="b-busca-estrutural-por-ast-nexus-query-em-nexus-ast" tabindex="-1">B. Busca Estrutural por AST (<code>nexus_query</code> em <code>nexus_ast</code>) <a class="header-anchor" href="#b-busca-estrutural-por-ast-nexus-query-em-nexus-ast" aria-label="Permalink to &quot;B. Busca Estrutural por AST (`nexus_query` em `nexus_ast`)&quot;">​</a></h3><ul><li><strong>Query:</strong> <code>&quot;run_decay&quot;</code></li><li><strong>Resultado do MCP:</strong> Identificou o nó AST L1 do arquivo [nomad/decay.rs](file:///var/home/bruno/repos/NEXUS/services/coordinator/src/nomad/decay.rs) (Node ID <code>2f850966-5f32-4dc3-be83-5621dfa7e0c2</code>), comprovando que o mapeamento estrutural local via <code>ast-grep</code> está ativo.</li></ul><h3 id="c-caminhada-topologica-nexus-adjacent" tabindex="-1">C. Caminhada Topológica (<code>nexus_adjacent</code>) <a class="header-anchor" href="#c-caminhada-topologica-nexus-adjacent" aria-label="Permalink to &quot;C. Caminhada Topológica (`nexus_adjacent`)&quot;">​</a></h3><ul><li><strong>Entrada:</strong> Nó de arquivo de [ingest.rs](file:///var/home/bruno/repos/NEXUS/services/coordinator/src/ingest.rs) (<code>573be0d4-821c-44d5-97da-09825af66181</code>).</li><li><strong>Resultado do MCP:</strong><ul><li><strong>Outbound:</strong> <code>depends_on:imports</code> para <code>embedding.rs</code> e <code>ast_chunker.rs</code>.</li><li><strong>Inbound:</strong> <code>part_of</code> vindo dos chunks L0 correspondentes.</li></ul></li><li><strong>Validação:</strong> As dependências mapeadas pelo MCP coincidem exatamente com os registros físicos do Postgres.</li></ul><hr><h2 id="_4-proximos-passos-wave-3" tabindex="-1">4. Próximos Passos (Wave 3) <a class="header-anchor" href="#_4-proximos-passos-wave-3" aria-label="Permalink to &quot;4. Próximos Passos (Wave 3)&quot;">​</a></h2><p>Com a estabilidade do pipeline de ingestão garantida e verificada:</p><ol><li><strong>Monitorar Conclusão da Ingestão:</strong> Aguardar a conclusão da ingestão assíncrona do restante dos arquivos (~200 pendentes).</li><li><strong>BFS Graph Walk (ADR-0020):</strong> Iniciar desenvolvimento de expansão T4 por BFS (graph walk query) após seeds semânticas no <code>query.rs</code>.</li><li><strong>Agent Stigmergy:</strong> Desenvolver a ferramenta <code>nexus_validate_link</code> no MCP para popular <code>ast_validated</code>.</li></ol>',23)])])}const m=o(r,[["render",d]]);export{p as __pageData,m as default};
